# dual explorer-H1 · S09-T3-A-E1
def fetch(retry=0):
    if retry < 2:
        raise TimeoutError("temp")
    return "ok"
attempt = 0
while True:
    try:
        print(fetch(attempt))
        break
    except TimeoutError:
        attempt += 1
        if attempt > 3:
            raise

# dual explorer-H1 · S09-T3-A-E2
def classify_error(e):
    if isinstance(e, TimeoutError):
        return "retryable"
    if isinstance(e, ValueError):
        return "data"
    return "other"
print(classify_error(TimeoutError()), classify_error(ValueError("x")))

